import React, { useState, useEffect, useRef } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const ReelsFeed = () => {
  const { user } = useAuth();
  const [reels, setReels] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [liked, setLiked] = useState({});
  const videoRefs = useRef([]);
  const containerRef = useRef(null);

  useEffect(() => {
    fetchReels();
  }, []);

  useEffect(() => {
    // Auto-play current video
    if (videoRefs.current[currentIndex]) {
      const ref = videoRefs.current[currentIndex];
      if (ref?.play) {
        ref.play().catch(() => {});
      }
    }
  }, [currentIndex]);

  const fetchReels = async () => {
    try {
      const [userReelsRes, tmdbReelsRes] = await Promise.all([
        api.get('/reels').catch(() => ({ data: [] })),
        api.get('/movie-reels').catch(() => ({ data: [] }))
      ]);

      const userReels = (userReelsRes.data || []).map(reel => ({
        ...reel,
        type: 'user',
        id: reel._id
      }));

      const tmdbReels = (tmdbReelsRes.data || []).map(reel => ({
        ...reel,
        type: 'tmdb'
      }));

      const combined = [];
      let userIdx = 0;
      let tmdbIdx = 0;

      while (userIdx < userReels.length || tmdbIdx < tmdbReels.length) {
        if (tmdbIdx < tmdbReels.length) combined.push(tmdbReels[tmdbIdx++]);
        if (tmdbIdx < tmdbReels.length) combined.push(tmdbReels[tmdbIdx++]);
        if (userIdx < userReels.length) combined.push(userReels[userIdx++]);
      }

      setReels(combined);
    } catch (error) {
      console.error('Error fetching reels:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleScroll = (e) => {
    const scrollTop = e.target.scrollTop;
    const height = e.target.clientHeight;
    const newIndex = Math.round(scrollTop / height);

    if (newIndex !== currentIndex && newIndex < reels.length && newIndex >= 0) {
      if (videoRefs.current[currentIndex]?.pause) {
        videoRefs.current[currentIndex].pause();
      }
      setCurrentIndex(newIndex);
    }
  };

  const handleLike = async (reel) => {
    try {
      if (reel.type === 'user') {
        await api.post(`/reels/${reel._id}/like`);
        setLiked((prev) => ({ ...prev, [reel._id]: !prev[reel._id] }));
        setReels(reels.map(r =>
          r._id === reel._id ? { ...r, likes: r.likes + 1 } : r
        ));
      } else {
        setLiked((prev) => ({ ...prev, [reel.id]: !prev[reel.id] }));
      }
    } catch (error) {
      console.error('Error liking reel:', error);
    }
  };

  const handleShare = (reel) => {
    let text = '';
    let url = '';

    if (reel.type === 'user') {
      text = `Check out this movie edit: "${reel.title}"`;
      url = window.location.origin;
    } else {
      text = `Check out ${reel.title} - trailer on Cineverse!`;
      url = reel.trailerKey ? `https://www.youtube.com/watch?v=${reel.trailerKey}` : window.location.origin;
    }

    if (navigator.share) {
      navigator.share({ title: 'Movie Reel', text, url }).catch(() => {});
    } else {
      navigator.clipboard.writeText(`${text}\n${url}`);
      alert('Link copied to clipboard!');
    }
  };

  if (loading) {
    return (
      <div className="w-full h-screen bg-gradient-to-b from-black via-gray-900 to-black flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-purple-600 border-t-cyan-400 rounded-full animate-spin mx-auto mb-4" />
          <p className="text-gray-300 text-lg">Loading reels...</p>
        </div>
      </div>
    );
  }

  if (reels.length === 0) {
    return (
      <div className="w-full h-screen bg-gradient-to-b from-black via-gray-900 to-black flex items-center justify-center">
        <div className="text-center">
          <p className="text-6xl mb-6">🎬</p>
          <h2 className="text-2xl font-bold text-white mb-2">No Reels Yet</h2>
          <p className="text-gray-400">Be the first to upload a movie edit!</p>
        </div>
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      className="w-full h-screen overflow-y-scroll snap-y snap-mandatory bg-black scroll-smooth"
      onScroll={handleScroll}
    >
      {reels.map((reel, index) => {
        const isUser = reel.type === 'user';
        const isActive = index === currentIndex;

        return (
          <div
            key={isUser ? reel._id : reel.id}
            className="relative w-full h-screen snap-center flex items-center justify-center bg-black overflow-hidden"
          >
            {/* Background Overlay */}
            <div className="absolute inset-0 bg-gradient-to-br from-black/40 via-transparent to-black/60 z-[5]" />

            {/* Content */}
            {isUser ? (
              // User Video
              <video
                ref={(el) => (videoRefs.current[index] = el)}
                className="w-full h-full object-contain"
                src={`http://localhost:5000${reel.videoUrl}`}
                loop
                playsInline
                muted={!isActive}
              />
            ) : (
              // TMDB Trailer
              <div className="w-full h-full flex items-center justify-center relative">
                {isActive && reel.trailerKey ? (
                  <iframe
                    className="w-full h-full"
                    src={`https://www.youtube.com/embed/${reel.trailerKey}?autoplay=1&mute=1&controls=1&modestbranding=1&rel=0&loop=1&playlist=${reel.trailerKey}`}
                    title={reel.title}
                    allow="autoplay; encrypted-media"
                    allowFullScreen
                    style={{ border: 'none' }}
                  />
                ) : (
                  <div className="relative w-full h-full flex items-center justify-center group">
                    <img
                      className="absolute inset-0 w-full h-full object-cover"
                      src={reel.poster}
                      alt={reel.title}
                    />
                    {reel.trailerKey && (
                      <div className="absolute inset-0 bg-black/40 group-hover:bg-black/50 flex items-center justify-center transition-colors z-10">
                        <button className="bg-white/20 hover:bg-white/30 backdrop-blur-sm p-5 rounded-full transition-all transform group-hover:scale-110">
                          <span className="text-6xl block">▶️</span>
                        </button>
                        <p className="absolute bottom-12 text-white/80 text-sm font-medium">Scroll to play</p>
                      </div>
                    )}
                    {!reel.trailerKey && (
                      <div className="absolute inset-0 bg-black/60 flex items-center justify-center backdrop-blur-sm z-10">
                        <div className="text-center">
                          <p className="text-5xl mb-4">🎬</p>
                          <p className="text-white font-semibold">Trailer Unavailable</p>
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            )}

            {/* Side Actions Bar */}
            <div className="absolute right-6 bottom-40 flex flex-col gap-8 z-20">
              {/* Like */}
              <button
                onClick={() => handleLike(reel)}
                className="flex flex-col items-center gap-2 group"
              >
                <div className="w-14 h-14 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-sm flex items-center justify-center transition-all group-hover:scale-110">
                  <span className="text-3xl">
                    {liked[isUser ? reel._id : reel.id] ? '❤️' : '🤍'}
                  </span>
                </div>
                <span className="text-xs text-white/70 font-semibold">
                  {isUser ? reel.likes : 0}
                </span>
              </button>

              {/* Share */}
              <button
                onClick={() => handleShare(reel)}
                className="flex flex-col items-center gap-2 group"
              >
                <div className="w-14 h-14 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-sm flex items-center justify-center transition-all group-hover:scale-110">
                  <span className="text-3xl">📤</span>
                </div>
                <span className="text-xs text-white/70 font-semibold">Share</span>
              </button>

              {/* Comment */}
              <button className="flex flex-col items-center gap-2 group">
                <div className="w-14 h-14 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-sm flex items-center justify-center transition-all group-hover:scale-110">
                  <span className="text-3xl">💬</span>
                </div>
                <span className="text-xs text-white/70 font-semibold">0</span>
              </button>

              {/* Info */}
              {!isUser && reel.trailerKey && (
                <a
                  href={`https://www.themoviedb.org/movie/${reel.id}`}
                  target="_blank"
                  rel="noreferrer"
                  className="flex flex-col items-center gap-2 group"
                >
                  <div className="w-14 h-14 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-sm flex items-center justify-center transition-all group-hover:scale-110">
                    <span className="text-3xl">ℹ️</span>
                  </div>
                  <span className="text-xs text-white/70 font-semibold">Info</span>
                </a>
              )}
            </div>

            {/* Bottom Info Bar */}
            <div className="absolute bottom-0 left-0 right-0 z-20">
              <div className="bg-gradient-to-t from-black via-black/80 to-transparent px-6 py-8 min-h-[200px] flex flex-col justify-end">
                <div className="max-w-md">
                  {/* Title and Badge */}
                  <div className="flex items-start gap-3 mb-3">
                    <h2 className="text-2xl font-bold text-white flex-1 leading-tight">{reel.title}</h2>
                    <span className={`text-xs font-bold px-3 py-1 rounded-full whitespace-nowrap mt-1 ${
                      isUser
                        ? 'bg-blue-600/80 text-blue-100'
                        : 'bg-purple-600/80 text-purple-100'
                    }`}>
                      {isUser ? 'Edit' : 'Trailer'}
                    </span>
                  </div>

                  {/* Creator Info */}
                  {isUser ? (
                    <div className="space-y-2">
                      {reel.uploadedBy && (
                        <p className="text-sm text-gray-300 flex items-center gap-2">
                          <span>👤</span> {reel.uploadedBy.name || 'Anonymous'}
                        </p>
                      )}
                      <div className="flex items-center gap-3 text-sm text-gray-400">
                        <span className="flex items-center gap-1">
                          <span>👁️</span> {reel.views}
                        </span>
                        <span>•</span>
                        <span>{new Date(reel.createdAt).toLocaleDateString()}</span>
                      </div>
                    </div>
                  ) : (
                    <div className="space-y-2">
                      <div className="flex items-center gap-2 text-sm text-gray-300">
                        <span>⭐ {reel.rating}</span>
                        <span>•</span>
                        <span>{reel.year}</span>
                        <span>•</span>
                        <span>{reel.genre}</span>
                      </div>
                      <p className="text-sm text-gray-400 line-clamp-2">{reel.plot}</p>
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Progress Indicator */}
            <div className="absolute top-6 left-1/2 -translate-x-1/2 z-20 bg-black/60 backdrop-blur-sm px-4 py-2 rounded-full">
              <p className="text-white text-sm font-semibold">
                {currentIndex + 1} / {reels.length}
              </p>
            </div>

            {/* Scroll Hint (First Reel Only) */}
            {currentIndex === 0 && (
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 text-white/50 text-xs animate-bounce z-20">
                Scroll to explore ↓
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
};

export default ReelsFeed;
